// Re-assert both post-states' page_array foralls so z3 instantiates the
// triggers (`post1_self_.page_array@[i]` and `post2_self_.page_array@[i]`).
assert(forall|i: int|
    #![trigger post1_self_.page_array@[i]]
    #![trigger pre_self_.page_array@[i]]
    0 <= i < NUM_PAGES && i != (index as int) ==>
        post1_self_.page_array@[i] =~= pre_self_.page_array@[i]);
assert(forall|i: int|
    #![trigger post2_self_.page_array@[i]]
    #![trigger pre_self_.page_array@[i]]
    0 <= i < NUM_PAGES && i != (index as int) ==>
        post2_self_.page_array@[i] =~= pre_self_.page_array@[i]);

// Pointwise: at every i, the two runs agree on `page_array@[i]`.
assert forall|i: int| 0 <= i < NUM_PAGES implies
    post1_self_.page_array@[i] =~= post2_self_.page_array@[i] by {
    if i == index as int {
        // At the modified slot, every field of post1/post2 mirrors pre_self_,
        // except `io_mappings` which is set to `io_mapping` in both runs.
        assert(post1_self_.page_array@[i].addr
            =~= post2_self_.page_array@[i].addr);
        assert(post1_self_.page_array@[i].state
            =~= post2_self_.page_array@[i].state);
        assert(post1_self_.page_array@[i].is_io_page
            =~= post2_self_.page_array@[i].is_io_page);
        assert(post1_self_.page_array@[i].rev_pointer
            =~= post2_self_.page_array@[i].rev_pointer);
        assert(post1_self_.page_array@[i].ref_count
            =~= post2_self_.page_array@[i].ref_count);
        assert(post1_self_.page_array@[i].owning_container
            =~= post2_self_.page_array@[i].owning_container);
        assert(post1_self_.page_array@[i].mappings
            =~= post2_self_.page_array@[i].mappings);
        assert(post1_self_.page_array@[i].io_mappings
            =~= post2_self_.page_array@[i].io_mappings);
    } else {
        // Outside `index`, both runs leave the slot equal to pre_self_.
        assert(post1_self_.page_array@[i] =~= pre_self_.page_array@[i]);
        assert(post2_self_.page_array@[i] =~= pre_self_.page_array@[i]);
    }
}

// Seq extensionality lifts the pointwise equality to view equality.
assert(post1_self_.page_array@ =~= post2_self_.page_array@);
